<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Alden Solution Providers</title>
    <style>
        body {
            font-family: Arial, sans-serif;
            margin: 0;
            padding: 0;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: flex-start;
            height: 100vh;
            padding-top: 50px;
        }
        .header {
            position: absolute;
            top: 10px;
            left: 20px;
            font-size: 24px;
            font-weight: bold;
        }
        h1 {
            font-size: 32px;
            margin-bottom: 30px;
            text-align: center;
        }
        .form-container {
            display: flex;
            flex-direction: column;
            gap: 20px;
            align-items: center;
            width: 80%; 
            max-width: 600px; 
            margin: 0 auto;
        }
        .row {
            display: flex;
            gap: 15px;
            width: 100%;
        }
        select {
            padding: 12px;
            font-size: 16px;
            border-radius: 5px;
            border: 1px solid #ccc;
            width: 100%;
        }
        input[type="text"] {
            padding: 12px;
            font-size: 16px;
            border-radius: 5px;
            border: 1px solid #ccc;
            width: 100%;
        }
        .search-row {
            display: flex;
            flex-direction: column;
            gap: 15px;
            width: 100%;
            position: relative;  
        }
        .search-icon {
            font-size: 18px;
        }
        .card {
            display: none; /* Hide the card */
            flex-direction: row;
            border: 1px solid black;
            padding: 15px;
            align-items: center; /* Align content vertically */
            gap: 10px; /* Add space between image and text */
            width: 100%;
            height: 20px;
        }

        .card img {
            width: 50px; /* Set a fixed width */
            height: 30px; /* Set a fixed height */
            object-fit: cover; /* Maintain aspect ratio */
        }

        .card h2 {
            font-size: 16px;
            font-weight: lighter;
        }


        #search-results {
            display: flex;
            flex-wrap: wrap;
            gap: 2px; /* Space between cards */
        }

        .result-item {
            margin-bottom: 20px;
            padding: 15px;
            background-color: #fafafa;
            border: 1px solid #e0e0e0;
            border-radius: 8px;
            transition: all 0.3s ease;
        }
        .result-item:hover {
            background-color: #f0f0f0;
            box-shadow: 0 4px 8px rgba(0, 0, 0, 0.1);
        }
        .result-item strong {
            font-size: 18px;
            color: #333;
        }
        .result-item p {
            font-size: 16px;
            color: #555;
            margin: 8px 0;
        }
        .result-item .similarity {
            font-size: 14px;
            font-weight: bold;
            color: #4CAF50;
        }
        .no-results {
            text-align: center;
            font-size: 18px;
            color: #888;
            padding: 20px;
            border-radius: 8px;
            background-color: #f9f9f9;
            border: 1px solid #ddd;
        }
        #loading-spinner {
            text-align: center;
            margin-top: 20px;
            font-size: 18px;
            color: #4CAF50;
            font-weight: bold;
        }
        #suggestion-box {
            border: 1px solid #ccc;
            top: 100%;
            height: auto;
            overflow-y: auto;
            background-color: #fff;
            width: calc(100% - 24px);
            position: absolute; 
            z-index: 1;
            display: none;
            border-radius: 5px;
            padding: 5px;
            z-index: 9999;
            overflow-y: auto;
        }
        .suggestion-item {
            padding: 10px;
            border-bottom: 1px solid #ddd;
            cursor: pointer;
            transition: background-color 0.3s ease;
        }
        .suggestion-item:hover {
            background-color: #f1f1f1;
        }

        .suggestion-item:last-child {
            border-bottom: none;
        }

        .suggestion-item p {
            margin: 0;
            font-size: 14px;
            color: #333;
        }
        #sector-list{
            position: absolute;
            top: 100%;
            left: 0;
            width: 100%;
            border: 1px solid #ccc;
            background: white;
            max-height: 150px;
            overflow-y: auto;
            list-style: none;
            margin: 0;
            padding: 0;
            display: none;
            z-index: 1000;
        }
    </style>
</head>
<body>

    <div class="header">Alden Solution Providers</div>

    <h1>Explore Softwares</h1>

    <div class="form-container">
    <div class="row">
            <div style="position: relative; width: 100%;">
                <input type="text" id="sector" placeholder="Enter sector" oninput="filterSectors()" style="width: 100%; padding: 8px; box-sizing: border-box;" />
                <ul id="sector-list"></ul>
            </div>
        </div>
        <div class="search-row">
            <div style="display: flex; flex-direction: row;">
                <input type="text" id="search-text" placeholder="Enter software requirement" required oninput="showSuggestions()">
            </div>
            <div id="suggestion-box" style="border: 1px solid #ccc; display: none;"></div>
            <div id="search-results">
                <div class="card" id="Brainvire" onclick="navigateTo('https://thealdenglobal.com/ai-segregation/brainvire.php')">
                    <img src="data:image/png;base64," alt="">
                <h2>Brainvire</h2>
                </div>
                <div class="card" id="Cogoport" onclick="navigateTo('')">
                    <img src="data:image/png;base64," alt="">
                    <h2>Cogoport</h2>
                </div>
                <div class="card" id="Crest" onclick="navigateTo('')">
                    <img src="data:image/jpeg;base64," alt="">
                    <h2>Crest</h2>
                </div>
                <div class="card" id="Datalabs India Solutions Private Limited" onclick="navigateTo('')">
                    <img src="data:image/jpeg;base64," alt="">
                    <h2>Datalabs India Solutions Private Limited</h2>
                </div>
                <div class="card" id="Elixia Tech" onclick="navigateTo('')">
                    <img src="data:image/jpeg;base64," alt="">
                    <h2>Elixia Tech</h2>
                </div>
                <div class="card" id="Inciflo" onclick="navigateTo('')">
                    <img src="data:image/jpeg;base64," alt="">
                    <h2>Inciflo</h2>
                </div>
                <div class="card" id="Inquizity" onclick="navigateTo('')">
                    <img src="data:image/jpeg;base64," alt="">
                    <h2>Inquizity</h2>
                </div>
                <div class="card" id="Intugine Technologies" onclick="navigateTo('')">
                    <img src="data:image/jpeg;base64," alt="">
                    <h2>Intugine Technologies</h2>
                </div>
                <div class="card" id="Lepton Software" onclick="navigateTo('')">
                    <img src="data:image/jpeg;base64," alt="">
                    <h2>Lepton Software</h2>
                </div>
                <div class="card" id="NEWAGENXT" onclick="navigateTo('')">
                    <img src="data:image/jpeg;base64," alt="">
                    <h2>NEWAGENXT</h2>
                </div>
                <div class="card" id="ORMAE" onclick="navigateTo('')">
                    <img src="data:image/jpeg;base64," alt="">
                    <h2>ORMAE</h2>
                </div>
                <div class="card" id="Qbit" onclick="navigateTo('')">
                    <img src="data:image/png;base64," alt="">
                    <h2>Qbit</h2>
                </div>
                <div class="card" id="Rocket Flyer Technology Pvt. Ltd." onclick="navigateTo('')">
                    <img src="data:image/jpeg;base64," alt="">
                    <h2>Rocket Flyer Technology Pvt. Ltd.</h2>
                </div>
                <div class="card" id="Saddle Point" onclick="navigateTo('')">
                    <img src="data:image/jpeg;base64," alt="">
                    <h2>Saddle Point</h2>
                </div>
                <div class="card" id="Shipsy" onclick="navigateTo('')">
                    <img src="data:image/png;base64," alt="">
                    <h2>Shipsy</h2>
                </div>
                <div class="card" id="Palms" onclick="navigateTo('')">
                    <img src="data:image/jpeg;base64," alt="">
                    <h2>Palms</h2>
                </div>
            </div>
        </div>
    </div>
    <div id="loading-spinner" style="display: none;">Loading...</div>

    <script>
        let sectors = []; // Global array to hold the fetched sectors

        async function loadSectors() {
            try {
                const response = await fetch('http://localhost:3000/get-sectors');
                const data = await response.json();
                sectors = data.sectors; // Store fetched sectors
            } catch (error) {
                console.error('Error fetching sectors:', error);
            }
        }

        function filterSectors() {
            const input = document.getElementById('sector').value.toLowerCase();
            const sectorList = document.getElementById('sector-list');
            sectorList.innerHTML = ''; // Clear previous results

            if (input) {
                const filteredSectors = sectors.filter(sector =>
                    sector.toLowerCase().startsWith(input)
                );

                filteredSectors.forEach(sector => {
                    const listItem = document.createElement('li');
                    listItem.textContent = sector;
                    listItem.style.padding = '8px';
                    listItem.style.cursor = 'pointer';
                    listItem.style.borderBottom = '1px solid #ddd';
                    listItem.onclick = () => {
                        document.getElementById('sector').value = sector;
                        sectorList.style.display = 'none'; // Hide list on selection
                    };
                    sectorList.appendChild(listItem);
                });

                sectorList.style.display = filteredSectors.length ? 'block' : 'none';
            } else {
                sectorList.style.display = 'none'; // Hide list if input is empty
            }
        }

        window.onload = loadSectors;



        let autocomplete_suggestions = []
        async function fetchSuggestions(sector) {
            try {
                const response = await fetch(`http://localhost:3000/suggestions?sector=${encodeURIComponent(sector)}`);
                if (!response.ok) {
                    throw new Error('Failed to fetch suggestions');
                }
                autocomplete_suggestions = await response.json();
                autocomplete_suggestions.sector = sector; 
                showSuggestions(); 
            } catch (error) {
                console.error('Error fetching suggestions:', error);
                autocomplete_suggestions = []; 
                displayErrorMessage("Failed to fetch suggestions."); 
            }
        }

        function getRandomSuggestions(suggestions) {
            // Get a random selection of 10 suggestions
            const randomSuggestions = [];
            while (randomSuggestions.length < 10 && suggestions.length > 0) {
                const randomIndex = Math.floor(Math.random() * suggestions.length);
                randomSuggestions.push(suggestions[randomIndex]);
                suggestions.splice(randomIndex, 1); // Remove the selected suggestion to avoid duplicates
            }
            return randomSuggestions;
        }

        document.addEventListener('DOMContentLoaded', function() {
            const input = document.getElementById('search-text');
            if (input) {
                input.addEventListener('focus', showSuggestions);
            }
        });

        function showSuggestions() {
            const input = document.getElementById('search-text');
            const suggestionBox = document.getElementById('suggestion-box');
            const sectorSelect = document.getElementById('sector'); 
            const userInput = input.value.toLowerCase();
            suggestionBox.innerHTML = ''; 

            if (userInput === '') {
                suggestionBox.style.display = 'none';
                return;
            }

            const selectedsector = sectorSelect.value;

            if (autocomplete_suggestions.length === 0 || autocomplete_suggestions.sector !== selectedsector) {
                fetchSuggestions(selectedsector);
            }

            if (autocomplete_suggestions && Array.isArray(autocomplete_suggestions.suggestions)) {
                const randomSuggestions = getRandomSuggestions([...autocomplete_suggestions.suggestions]);

                const filteredSuggestions = randomSuggestions.filter(item =>
                    item.toLowerCase().includes(userInput.toLowerCase())
                );

                if (filteredSuggestions.length > 0) {
                    suggestionBox.style.display = 'block';
                    suggestionBox.innerHTML = ''; 

                    filteredSuggestions.forEach(suggestion => {
                        const suggestionItem = document.createElement('div');
                        suggestionItem.classList.add('suggestion-item');
                        suggestionItem.innerText = suggestion;
                        suggestionItem.onclick = () => {
                            input.value = suggestion; 
                            suggestionBox.style.display = 'none'; 
                            searchSoftware(); 
                        };
                        suggestionBox.appendChild(suggestionItem);
                    });
                } else {
                    suggestionBox.style.display = 'none';
                }
            } else {
                suggestionBox.style.display = 'none'; 
                displayErrorMessage("Failed to fetch valid suggestions.");
            }
        }

        // Additional code like `fetchSuggestions`, `getRandomSuggestions`, and others should be here as well.


        document.getElementById('search-text').addEventListener('keydown', (event) => {
            if (event.key === 'Enter') {
                event.preventDefault(); 
                searchSoftware(); 
            }
        });

        function displayErrorMessage(message) {
            const errorElement = document.getElementById("error-message");
            if (errorElement) {
                errorElement.textContent = message;
                errorElement.style.display = "block"; 
            }
        }

        function searchSoftware(event) {
            const sector = document.getElementById('sector').value;
            const searchText = document.getElementById('search-text').value;
            if (!sector || !searchText) {
                alert('Please fill in both fields!');
                return;
            }
            const loadingSpinner = document.getElementById('loading-spinner');
            loadingSpinner.style.display = 'block';
            fetch('http://localhost:3000/get_similarities', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({ sector: sector, input: searchText })
            })
            .then(response => response.json()) 
            .then(data => {
                loadingSpinner.style.display = 'none';
                if (data.length > 0) {
                    const searchResultsContainer = document.getElementById('search-results');
                    const allCards = Array.from(searchResultsContainer.getElementsByClassName('card')); 
                    allCards.forEach(card => {
                        card.style.display = 'none'; 
                    });
                    data.forEach(leadId => {
                        const matchingCard = allCards.find(card => card.id.trim().toLowerCase() === leadId.trim().toLowerCase());
                        if (matchingCard) {
                            matchingCard.style.display = 'block'; 
                            searchResultsContainer.appendChild(matchingCard); 
                        } else {
                            console.warn(`No card found for ID: ${leadId}`); 
                        }
                    });

                } else {
                    alert('No matching data found!');
                }
            })
            .catch(error => {
                console.error('Error fetching data:', error); 
                loadingSpinner.style.display = 'none'; 
            });
        }
    </script>
</body>
</html>
